UPDATE jobs SET user_contributed_json = '{"way":"우정사업본부가 실시하는 집배원 공개채용 시험에 합격하면 된다.[1] 별도의 학력 제한은 없으나 체력시험(오래달리기, 윗몸일으키기 등)을 통과해야 하며, 이륜자동차 운전면허(125cc 이상)도 필요하다.[2] 일부는 우편물류 인턴 과정을 거쳐 정규직으로 전환된다.[3]","overviewSalary":{"sal":"공무원 집배원의 평균 연봉은 약 3,500만~4,500만 원이며[1], 야간·휴일 근무 수당이 추가된다.[2]","source":"우정사업본부, 커리어넷(2024)"},"overviewProspect":{"main":"전자상거래 성장으로 소화물 배달 수요는 증가하나[1], 전통 우편물(서신류) 물량은 지속적으로 감소하는 추세이다.[2]","source":"한국고용정보원(2024)"},"trivia":"집배원은 하루 평균 500~800통의 우편물을 배달하며, 자전거·오토바이·차량 등 다양한 이동 수단을 사용한다.[1] 1884년 갑신정변 당시 홍영식이 설립한 우정총국이 한국 근대 우편 제도의 시작이다.[2] 최근 드론을 이용한 도서산간 지역 무인 우편 배달 시범사업이 시행되고 있다.[3]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"야외 배달 업무 특성상 폭염·폭설 등 악천후에도 근무해야 한다. 이른 아침 출근과 배달량에 따른 야간 연장도 발생한다.","socialDetail":"지역사회 구석구석을 잇는 우편 서비스로 사회 기여도가 높으며, 고령층이나 격오지 주민에게 생활 연결 역할을 담당한다."},"detailReady":{"curriculum":["이륜자동차(오토바이) 운전면허 취득","체력검정 준비(오래달리기·윗몸일으키기)","우편업무 관련 법령 기초 학습"],"recruit":["우정사업본부 집배원 공개채용 응시","계약직 우편배달원 → 정규직 전환","우편물류센터 취업 후 이동"],"training":["물류관리사 자격 취득","위험물 취급 기초 교육","우편 전산 시스템 활용 능력 향상"]},"sidebarJobs":["선박갑판원","선박기관사","우정실무원","우편물집배원","우편원","택배원","하역·적재종사원"],"sidebarMajors":["물류학과","유통물류과","유통경영과","물류시스템공학과","경영학과"],"sidebarCerts":["물류관리사","이륜자동차운전면허","유통관리사","위험물취급기능사","지게차운전기능사"],"heroTags":["집배원","우체부","우편배달","우정사업본부","공무원채용","집배원공채"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"우정사업본부 채용공고","url":"https://www.koreapost.go.kr/"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewSalary.sal":[{"id":4,"text":"우정사업본부","url":"https://www.koreapost.go.kr/"},{"id":5,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"trivia":[{"id":8,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":9,"text":"우정사업본부 역사","url":"https://www.koreapost.go.kr/"},{"id":10,"text":"과학기술정보통신부","url":"https://www.msit.go.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"detailWlb.socialDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}]}}' WHERE id = '1765283493607565';
UPDATE jobs SET user_contributed_json = '{"way":"식품공학, 식품영양학 관련 학과를 졸업하거나 직업훈련을 이수하면 취업에 유리하다.[1] 식품 제조업체, 농수산물 유통 회사, 담배 제조사 등에서 품질 검사원·등급 판정원으로 시작하는 것이 일반적이며[2], 품질관리 경력을 쌓아 QA 전문가나 관리자로 성장할 수 있다.[3]","overviewSalary":{"sal":"평균 연봉은 약 2,500만~3,500만 원 수준이며[1], 식품 대기업 품질관리직은 4,000만 원 이상도 가능하다.[2]","source":"워크넷 직업정보, 커리어넷(2024)"},"overviewProspect":{"main":"식품 안전 규제 강화와 소비자 인식 향상으로 품질관리 인력 수요는 꾸준히 유지될 전망이다.[1] 단, 자동화 검사 장비 도입으로 단순 검사 업무는 감소할 수 있다.[2]","source":"한국고용정보원(2024)"},"trivia":"식품등급원은 색상·형태·냄새·크기 등 수십 가지 기준으로 식품을 판별하며, 훈련된 오감이 가장 중요한 도구이다.[1] 담배 등급원은 담배잎의 색깔·향·탄력을 기준으로 수십 단계로 분류하는 고도의 전문 기술을 보유한다.[2] 우리나라 쌀 등급제는 1등급부터 등외까지 5단계로 나뉘며, 등급에 따라 유통 가격 차이가 최대 30%에 달한다.[3]","detailWlb":{"wlb":"보통","social":"보통이하","wlbDetail":"제조 현장 특성상 교대 근무가 있을 수 있으며, 대형 납품 마감 시기에는 야근이 발생한다. 서 있는 시간이 길어 체력 부담이 있다.","socialDetail":"식품 안전을 지키는 역할로 소비자 보호에 기여하지만, 외부 노출이 적어 사회적 인지도는 낮은 편이다."},"detailReady":{"curriculum":["식품공학·식품영양학 전공 또는 직업훈련 이수","식품위생법 및 관련 법령 학습","HACCP, ISO 22000 등 품질관리 시스템 교육"],"recruit":["식품 제조업체 품질관리직 공채","농수산물 유통 회사 품질검사 담당 채용","담배제조사(KT&G 등) 기술직 지원"],"training":["식품산업기사·기사 자격 취득","HACCP 관리자 과정 이수","ISO 내부심사원 과정 수료"]},"sidebarJobs":["곡물등급원","김치·밑반찬 제조종사원","원목등급원","정육원 및 도축원","합판등급원"],"sidebarMajors":["식품공학과","식품영양학과","식품가공과","식품영양과","식품자원경제학과"],"sidebarCerts":["식품산업기사","식품기사","위생사","HACCP관리자","품질경영산업기사"],"heroTags":["식품등급원","품질검사","식품안전","식품품질관리","등급판정","식품기사"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"한국식품안전관리인증원","url":"https://www.haccp.or.kr/"}],"overviewSalary.sal":[{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":5,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"식품의약품안전처","url":"https://www.mfds.go.kr/"}],"trivia":[{"id":8,"text":"식품의약품안전처","url":"https://www.mfds.go.kr/"},{"id":9,"text":"KT&G 기술정보","url":"https://www.ktng.com/"},{"id":10,"text":"국립농산물품질관리원","url":"https://www.naqs.go.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"detailWlb.socialDetail":[{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283523245288';
UPDATE jobs SET user_contributed_json = '{"way":"대학에서 법학, 경영학, 금융학 등을 전공하면 유리하다.[1] 손해보험사·생명보험사의 공채 또는 수시 채용을 통해 입사하며, 보험 심사·손해사정 업무를 담당하게 된다.[2] 손해사정사 자격을 취득하면 전문성을 크게 높일 수 있으며, 독립 손해사정사로 개업하는 것도 가능하다.[3]","overviewSalary":{"sal":"평균 연봉은 약 3,500만~5,500만 원이며[1], 대형 보험사 손해사정 전문가는 6,000만 원 이상도 가능하다.[2]","source":"워크넷 직업정보, 커리어넷(2024)"},"overviewProspect":{"main":"보험 산업의 성장과 함께 손해보상 전문 인력 수요는 안정적이며[1], 자동차·의료 분야 보상 업무는 꾸준히 유지될 전망이다.[2]","source":"한국고용정보원(2024)"},"trivia":"보험보상사무원은 보험 사기 적발 업무도 담당하며, 국내 보험 사기 적발 금액은 연간 1조 원을 넘어선다.[1] 손해사정사는 보험계약자와 보험사 사이에서 손해액을 객관적으로 산정하는 독립적 전문가이다.[2] AI 기술 도입으로 일부 보험사는 단순 보상 심사를 자동화하고 있어, 복잡 사건 처리 역량이 더욱 중요해지고 있다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"보험 보상 시즌(자연재해·교통사고 다발 시기)에는 업무가 집중되나, 평상시에는 비교적 규칙적인 근무가 가능하다.","socialDetail":"고객의 재정적 위기 상황에서 신속·공정한 보상을 제공하는 역할로 사회적 신뢰와 감사를 받는 직업이다."},"detailReady":{"curriculum":["법학·경영·금융학 전공 선택","보험 관련 법규 및 약관 학습","자동차·의료 분야 손해 지식 습득"],"recruit":["손해보험사 보상팀 공채 지원","생명보험사 보험금 심사팀 채용","손해사정법인 입사"],"training":["손해사정사(1종·2종) 자격 취득","보험계리사 준비","의료관련 손해 실무 전문 교육"]},"sidebarJobs":["보험보유계약관리원","보험인수심사원(언더라이터)","신용추심원","은행사무원","증권사무원","출납창구사무원"],"sidebarMajors":["금융·보험학과","경영학과","금융경영과","법학과","경영회계정보과"],"sidebarCerts":["손해사정사(1종·2종)","보험계리사","CFP(국제공인재무설계사)","보험중개사","생명보험대리점자격"],"heroTags":["보험보상사무원","손해사정사","보험사무원","손해보험","보험취업","보상심사"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"금융감독원","url":"https://www.fss.or.kr/"}],"overviewSalary.sal":[{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":5,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"보험연구원","url":"https://www.kiri.or.kr/"}],"trivia":[{"id":8,"text":"금융감독원 보험사기신고센터","url":"https://www.fss.or.kr/"},{"id":9,"text":"한국손해사정사회","url":"https://www.kicaa.or.kr/"},{"id":10,"text":"보험연구원","url":"https://www.kiri.or.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"detailWlb.socialDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}]}}' WHERE id = '1765283430223155';
UPDATE jobs SET user_contributed_json = '{"way":"직업훈련기관 또는 건설 현장 견습을 통해 배관 실무를 익히는 것이 기본 경로이다.[1] 배관기능사 자격을 취득하면 취업에 유리하며, 공업배관·가스 분야는 별도의 전문 자격이 필요할 수 있다.[2] 경력을 쌓아 배관기사나 현장 시공관리자로 성장하는 길도 열려 있다.[3]","overviewSalary":{"sal":"일당 기준 15만~25만 원 수준이며[1], 연간 환산 시 3,500만~5,000만 원 내외이다.[2]","source":"워크넷 직업정보, 대한설비건설협회(2024)"},"overviewProspect":{"main":"건설·플랜트 산업 수요에 연동되며[1], 노후 배관 교체 및 친환경 에너지 인프라 확장으로 꾸준한 수요가 지속될 전망이다.[2]","source":"한국고용정보원(2024)"},"trivia":"배관공은 물, 가스, 증기, 화학물질 등 다양한 유체를 다루며, 잘못된 배관 하나가 대형 사고로 이어질 수 있다.[1] 국내 최대 규모의 지역난방 배관망은 서울에만 약 800km 이상 매설되어 있다.[2] 고난도 공업용 배관공(피팅·용접 포함)은 해외 플랜트 현장에 파견되어 연간 수천만 원의 출장 수당을 받기도 한다.[3]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"건설 현장 특성상 이른 아침 출근과 날씨에 따른 야외 작업이 많다. 공사 마감 시기에는 야근과 휴일 근무가 빈번하게 발생한다.","socialDetail":"건물의 급수·배수·가스·소방 시스템을 구성하는 필수 기술직으로, 안전하고 쾌적한 생활환경을 만드는 데 직접 기여한다."},"detailReady":{"curriculum":["배관 직업훈련원 과정 수료","배관기능사 자격 시험 준비","가스·용접 기초 기술 습득"],"recruit":["건설사 배관 하도급 업체 취업","플랜트 전문 시공사 현장직 입사","가스·수도 공사 전문 업체 채용 지원"],"training":["배관기사 자격 승급","가스기능사·가스산업기사 취득","고압가스 안전관리자 과정 이수"]},"sidebarJobs":["가스인입배관공","건축배관공","공업배관공","광산배관공","철도차량배관공","항공기유압배관공"],"sidebarMajors":["건축·설비공학과","건축설비과","건설정보과","건축공학과","토목공학과"],"sidebarCerts":["배관기능사","배관기사","가스기능사","가스산업기사","고압가스관련기능사"],"heroTags":["건설배관공","배관공","배관기능사","배관기사","설비공","건설취업"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"대한설비건설협회","url":"https://www.kmcca.or.kr/"}],"overviewSalary.sal":[{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":5,"text":"대한설비건설협회","url":"https://www.kmcca.or.kr/"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"trivia":[{"id":8,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":9,"text":"한국지역난방공사","url":"https://www.kdhc.co.kr/"},{"id":10,"text":"해외건설협회","url":"https://www.icak.or.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"detailWlb.socialDetail":[{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283499348417';
